@ARTICLE{10.1016/j.xcrm.2026.102698,
	author = {Zhao W and Zhou X and Zhao X and Tian H and Su Y and Zhao S and Liu M and Zhang Q and Chen L and Li X and Liu D and Li J and Li L and Wang Y and Li X and Yan J and Chen W and Liu B and Zhu C and Zeng W},
	title = {CAR-M2 immunotherapy resolves renal fibrosis via revascularization and apoptosis of profibrotic Cxcr2(+) endothelial cells.},
	journal = {Cell Rep Med},
	year = {2026},
	abstract = {Renal fibrosis is a common outcome of chronic kidney disease (CKD), forming a fibrotic niche characterized by fibroblast activation and vascular rarefaction. Currently, there are no effective treatment strategies targeting fibrotic niche. Here, we show that chimeric antigen receptor-modified M2 macrophages (CAR-M2) targeting FAP and secreting interleukin (IL)-4 are delivered via an injectable HAMA-CS hydrogel beneath the renal subcapsule and attenuate renal fibrosis while promoting renal revascularization. The single-cell RNA sequencing reveals the heterogeneity and interaction of stroma and endothelial cells (ECs). A fibrosis-related Cxcr2+ EC subset is identified, and its specific depletion effectively mitigates renal fibrosis. Further results reveal that CAR-M2 can release matrix metalloproteinase 2 (MMP2) in close proximity to activate retinoid X receptor alpha (Rxra) in the Cxcr2+ ECs and further triggers its mitochondrial autophagy, leading to apoptosis. Our research provides innovative strategies and proof of principle for the immunotherapy of organ fibrosis.},
	doi = {10.1016/j.xcrm.2026.102698},
	pmid = {41887221}
}

@ARTICLE{10.1038/s41419-026-08644-x,
	author = {Li X and Melchinger I and Chen Y and Guo J and Cantley LG and Xu L},
	title = {CXCR6+ T cells promote apoptosis and necroptosis in proximal tubules during AKI-to-CKD transition.},
	journal = {Cell Death Dis},
	year = {2026},
	abstract = {Acute kidney injury (AKI) can progress to chronic kidney disease (CKD) in the setting of maladaptive repair characterized by tubular atrophy, inflammation, and fibrosis. Programmed cell death is a key driver of proximal tubule (PT) loss, yet how immune infiltration promotes tubular injury and death remains incompletely understood. Using a mouse model of maladaptive repair, we integrated bulk and single-cell RNA sequencing with immunohistochemistry and protein analyses to define immune-epithelial interactions during AKI-to-CKD transition. Injured kidneys exhibited loss of healthy PTs, expansion of injured PT subsets, and late-stage T cell accumulation. Apoptotic and necroptotic signaling pathways were markedly upregulated, particularly in VCAM1+ PT cells. Cell-cell interaction analysis identified macrophage-derived Cxcl16 as the dominant chemokine mediating recruitment of Cxcr6+ T cells. Genetic deletion of Cxcr6 reduced renal T cell accumulation, cytotoxic effector expression, and activation of apoptotic (cleaved caspase-3, Bax) and necroptotic signaling (MLKL, phospho-MLKL) in PT cells. Accordingly, Cxcr6-/- mice displayed preserved PT differentiation, reduced fibrosis, and improved renal function. Together, these findings identify Cxcr6+ T cells as key mediators of immune-driven tubular cell death during maladaptive repair and suggest that targeting the CXCL16-CXCR6 axis may mitigate tubular injury and slow AKI-to-CKD progression.},
	doi = {10.1038/s41419-026-08644-x},
	pmid = {41876471}
}

@ARTICLE{10.1681/ASN.0000001073,
	author = {Cozzolino M and Ciceri P},
	title = {Apoptotic Bodies in Kidney Disease: Orchestrators of Inflammation, Fibrosis, and Repair.},
	journal = {J Am Soc Nephrol},
	year = {2026},
	abstract = {Apoptotic bodies are membrane-bound vesicles generated during the terminal stages of programmed cell death and traditionally viewed as inert cellular debris. Emerging evidence, however, positions apoptotic bodies as dynamic mediators of intercellular communication with critical roles in renal physiology and pathology. In the healthy kidney, efficient efferocytosis of apoptotic bodies maintains tissue homeostasis by ensuring immunologically silent clearance of apoptotic remnants. In acute kidney injury (AKI), extensive tubular epithelial apoptosis generates a high burden of apoptotic bodies that can amplify inflammation, endothelial dysfunction, and adaptive immune activation when clearance is impaired, yet promote resolution and epithelial repair when efficiently removed. In chronic kidney disease (CKD), persistent low-grade apoptosis combined with defective efferocytosis leads to progressive accumulation of apoptotic bodies in the interstitium, where their bioactive cargo-including DAMPs, cytokines, growth factors, and profibrotic microRNAs-drives fibroblast activation, extracellular matrix expansion, and fibrosis. In the vasculature, apoptotic bodies derived from vascular smooth muscle cells act as nucleation sites for calcium-phosphate crystal deposition, linking apoptosis to the development of medial vascular calcification in CKD. Together, these findings highlight apoptotic bodies as active regulators of injury, inflammation, fibrosis, regeneration, and vascular pathology. Understanding the determinants of their pathogenic versus reparative effects could yield new biomarkers and therapeutic strategies, including modulation of efferocytosis, targeting apoptotic body-derived signaling pathways, and engineering apoptotic bodies-based delivery systems.},
	doi = {10.1681/ASN.0000001073},
	pmid = {41774507}
}

@ARTICLE{10.7150/thno.123986,
	author = {Huang J and Chen Z and Zhong F and Zheng R and Zhang D and Su J and Zhong Y and Fang X and Li D and Guan Y and Geng H},
	title = {MUC20 alleviates kidney fibrosis by modulating pyroptosis through the MET/RAS/STING axis.},
	abstract = {Rationale: Mucins are epithelial transmembrane glycoproteins involved in inflammation and kidney dysfunction, yet the role of the transmembrane mucin MUC20 in renal injury and fibrosis remains unclear. This study aimed to define the functional significance and underlying mechanisms of MUC20 in kidney fibrosis. Methods: Muc20-deficient mice and tubular epithelial cell models were used to evaluate renal fibrosis and pyroptosis in induced kidney injury. Molecular and biochemical approaches were applied to assess protein interactions, RAS activation, 2'3'-cGAMP production, cGAS-STING signaling, lysosomal integrity, potassium efflux, and NLRP3 inflammasome activation. Results: Loss of MUC20 significantly exacerbated renal fibrosis and increased pyroptosis in tubular epithelial cells. Mechanistically, MUC20 interacted with MET to promote RAS activation. MUC20 deficiency decreased GTP-bound RAS levels, leading to increased 2'3'-cGAMP production and activation of the cGAS-STING pathway. STING activation induced lysosomal membrane permeabilization, potassium efflux, and subsequent NLRP3 inflammasome-mediated pyroptosis. Conclusions: MUC20 acts as a key protective regulator in kidney by restraining RAS-cGAS-STING-NLRP3-driven pyroptosis and fibrotic progression. Targeting MUC20-related signaling pathways may offer therapeutic potential for kidney fibrosis and chronic kidney disease.},
	doi = {10.7150/thno.123986},
	pmid = {41695494 [Indexed for MEDLINE]},
	note = {PMC12906183}
}

