@ARTICLE{10.1038/s42003-026-09603-0,
	author = {Hayashi H and Miura Y and Iwazu Y and Mukai H and Mori Y and Kuchimaru T and Ohno N and Aiba T and Okada R and Kamimura D and Shiba D and Kurosu H and Kuro-O M},
	title = {Bone mineral loss damages renal tubules in mice.},
	journal = {Commun Biol},
	year = {2026},
	abstract = {Fibroblast growth factor-23 (FGF23) is a bone-derived hormone that promotes urinary phosphate excretion in response to phosphate loading. While essential for phosphate homeostasis, elevated FGF23 increases phosphate concentration in the renal tubular fluid, promoting calcium-phosphate crystal formation and tubular injury. Here we show that bone resorption mobilizes phosphate into the circulation and mimics the pathophysiology of dietary phosphate loading. Enhanced bone resorption, induced by soluble receptor activator of NF-κB ligand (sRANKL) administration or microgravity exposure on the International Space Station, increased circulating FGF23 levels and caused renal tubular injury in mice. Pre-treatment with bisphosphonate, an inducer of osteoclast apoptosis, prevented sRANKL-induced increases in FGF23 and tubular damage. These findings suggest that bone mineral loss may contribute to renal tubular injury in clinical settings, including immobilization, osteoporosis, and chronic kidney disease-mineral bone disorder.},
	doi = {10.1038/s42003-026-09603-0},
	pmid = {41571870 [Indexed for MEDLINE]},
	note = {PMC12929778}
}

@ARTICLE{10.1016/j.kint.2025.12.025,
	author = {Wagner CS and Elias RM and Nickolas TL and Martin A and Martinez-Calle M and Oliveira IB and Coelho AC and Dos Reis LM and Jorgetti V and David V, Moysés RMA},
	title = {Uremia and parathyroid hormone have distinct effects on bone protein and gene expression.},
	journal = {Kidney Int},
	year = {2026},
	abstract = {INTRODUCTION: Chronic kidney disease (CKD)-associated osteoporosis is highly prevalent and increases the risk of fractures. Current therapy aims to preserve normal bone turnover, by maintaining parathyroid hormone (PTH) at relatively adequate levels. However, these patients continue to experience fractures. METHODS: To assess potential adverse effects of PTH on bone, we examined bone histology and osteocytic gene and protein expression in 76 patients receiving hemodialysis compared to that of 33 control individuals. RESULTS: Using bulk bone tissue RNAseq, we observed that CKD is associated with enhanced inflammatory signaling, increased cell death, impaired osteoblastic differentiation, and reduced bone mass, consistent with low osteocyte count and increased apoptosis. Patients with elevated PTH levels showed an attenuation of these alterations, but exhibited increased expression of genes related to fibrosis, matrix apposition, and bone remodeling, leading to increased cortical porosity. CONCLUSIONS: CKD induces inflammation and cell death in bone. However, elevated PTH levels exhibited dual effects that were both protective and detrimental to bone tissue quality and strength. Our findings suggest that combining anabolic agents with relatively low PTH levels may be a potential approach to improve bone quality in CKD. This hypothesis warrants further investigation in future studies.},
	doi = {10.1016/j.kint.2025.12.025},
	pmid = {41571099 [Indexed for MEDLINE]}
}

@ARTICLE{10.1172/jci.insight.194604,
	author = {Zhao Z and Yan Q and Zhou S and Liu F and Liu Y and Ren J and Pan S and Liu Z and Liu D and Liu Z and Duan J},
	title = {MYO1C is a urinary extracellular vesicle biomarker and mediator of podocyte injury in diabetic nephropathy.},
	journal = {JCI Insight},
	year = {2026},
	abstract = {Type 2 diabetic nephropathy (T2DN) is a major complication of type 2 diabetes and a leading cause of chronic kidney disease. This study aimed to explore Myosin IC (MYO1C) as both a candidate biomarker and elucidate its role as a mechanistic mediator of podocyte injury in T2DN. Using urinary extracellular vesicle RNA biomarkers identified from a training and validation cohort of 33 type 2 diabetes and 40 patients with T2DN, we developed a machine learning diagnostic model for T2DN. The model achieved an AUC of 0.877 in validation and performed well in an independent test cohort with an AUC of 0.824. MYO1C was identified as the most influential feature in the final model. Mechanistic investigations in vitro and in vivo revealed that high glucose and high-fat conditions induced podocyte injury, inflammation, and apoptosis, with increased MYO1C expression. MYO1C knockdown in vitro and in vivo reduced podocyte damage and inflammatory responses. MYO1C overexpression enhanced p38, p-CREB, and TNF-α levels, while p38 inhibition mitigated these effects. These findings support MYO1C not only as a potential urinary biomarker for T2DN but also as a key pathogenic driver that promotes podocyte injury via p38 MAPK signaling.},
	doi = {10.1172/jci.insight.194604},
	pmid = {41569692 [Indexed for MEDLINE]}
}

@ARTICLE{10.1681/ASN.0000000902,
	author = {Xu C and Cheung CY and Zhong J and Lin Y and Fong CH and Jiang X and Jia X and Lui DT and Lee CH and Lam KS and Xu A},
	title = {A Five-Plasma Protein-Based Algorithm for Predicting Incident CKD in Type 2 Diabetes.},
	journal = {J Am Soc Nephrol},
	year = {2025},
	abstract = {KEY POINTS: Proteomics analyses consistently identified nine independent protein predictors for CKD in both Chinese and European participants with type 2 diabetes. A novel prediction model, "eGFR+five-protein panel predicting CKD," reliably predicted CKD with good performance (area under the receiver operating characteristic curve ≥0.80). The new "eGFR+five-protein panel predicting CKD" model exhibited superior performance over traditional clinical models. BACKGROUND: Currently, there is a lack of reliable biomarkers for noninvasive prediction of CKD in patients with diabetes. This study aimed to identify novel protein predictors and construct a prediction model for incident CKD in participants with type 2 diabetes applicable across different populations. METHODS: A targeted Olink plasma proteomics profiling analysis, involving 368 proteins, was conducted in a nested case-control study comprising 132 incident CKD cases and 132 non-CKD controls, matched for age, sex, duration of diabetes, and eGFR, recruited from a long-term prospective cohort of Chinese type 2 diabetes participants (median approximately 9-year follow-up). False discovery rate was applied for multiple testing corrections. A q -value <0.2 was considered statistically significant. Three machine-learning approaches (Boruta, support vector machine, and eXtreme gradient boosting) were used for feature selection. Independent associations of proteins with incident CKD with adjustments for conventional clinical risk factors were examined in the training set ( n =1580, including 173 incident CKD cases and 1407 non-CKD controls; 70%) of the UK Biobank Pharma Proteomics Project (UKB-PPP) (median approximately 13.5-year follow-up). The least absolute shrinkage and selection operator-based Cox-regression analysis was used to develop the prediction model, which was subsequently validated in the testing set ( n =677, including 85 incident CKD cases and 592 non-CKD controls; 30%) of UKB-PPP. RESULTS: Among the 18 identified protein features predictive of incident CKD, 12 showed significant associations with consistent direction of effects in both cohorts. A prediction model ("eGFR+five-protein panel predicting CKD [eGFR+FPPC]") combining eGFR and five proteins (alpha-1-microglobulin/bikunin precursor, matrix metallopeptidase 7, placental growth factor, TNF-related apoptosis-inducing ligand receptor 2, and kidney injury molecule-1) was constructed and validated in the testing and training sets of the UKB-PPP, respectively. The "eGFR+FPPC" model achieved superior predictive performance in both training (area under the receiver operating characteristic curve [95% confidence interval]: 0.82 [0.79 to 0.85]) and testing (area under the receiver operating characteristic curve [95% confidence interval]: 0.80 [0.74 to 0.86]) sets of UKB-PPP and yielded fewer indeterminate results compared with conventional clinical models. CONCLUSIONS: The "eGFR+FPPC" model performed better than conventional clinical models in predicting incident CKD in type 2 diabetes participants across different populations.},
	doi = {10.1681/ASN.0000000902},
	pmid = {41563825}
}

@ARTICLE{10.1681/ASN.0000001002,
	author = {Nath KA and Singh RD and Croatt AJ and Juncos LA},
	title = {The Aging Kidney and Acute Kidney Injury.},
	journal = {J Am Soc Nephrol},
	year = {2025},
	abstract = {Aging is unavoidable and driven, at least in part, by the biologic process termed senescence. Senescence is characterized by cell cycle arrest incurred by one or more stressors wherein there is cellular upregulation of cyclin-dependent kinase inhibitors, p16 Ink4a and/or p21 Cip1 . Senescent cells are metabolically active and resistant to apoptosis, have increased β -galactosidase activity, and express a senescence-associated secretory phenotype (SASP). The SASP produces an array of inflammatory, cytotoxic, fibrotic, and vasoactive factors. Senescence is a diffusible process as, largely through the SASP, a focus of senescent cells can recruit adjacent cells and cells in distant organs, thereby expanding its scope way beyond its original focus. Senescence predisposes not only to chronic diseases (including CKD) but also acute processes (including AKI). This review provides evidence that age increases the risk of human AKI and summarizes clinical factors that predispose older individuals to AKI. It provides an overview of the biology of senescence, and it discusses the role of intrarenal senescent cells in the pathogenesis of AKI, the significance of the extrarenal milieu and distant organs in predisposing to AKI with age, heme as a prosenescent species, and the role of senescence in the AKI to CKD transition. The risk for AKI with aging, in large part, reflects the fact that virtually all processes implicated in AKI, irrespective of age, occur as the kidney ages. Processes discussed include senescent cells, vascular responses, diabetes, impaired NAD + content, sirtuin expression, mitochondrial dysfunction, impaired autophagy, epigenetic changes, telomere shortening, impaired nephroprotectant expression, inflammaging, and immunosenescence. The review concludes by discussing the basis for senolytics (agents that kill senescent cells), senomorphics (agents that block SASP factors), and other aspects of senotherapies.},
	doi = {10.1681/ASN.0000001002},
	pmid = {41563815}
}

@ARTICLE{10.1681/ASN.0000000964,
	author = {Bachir H and Krausel V and Buerger F and Hamed M and Heitplatz B, van Marck V and Paraparan V and Freckmann H and Bayraktar S, Vollenbröker B and Weide T and Rozhdestvensky TS and Skryabin BV and Antonin W, Pavenstädt H and Hildebrandt F and Braun DA},
	title = {Mechanisms of Podocyte Injury Due to Loss of the Nucleoporin NUP93.},
	journal = {J Am Soc Nephrol},
	year = {2025},
	abstract = {KEY POINTS: Loss of NUP93 caused progressive glomerular disease in mice. Nuclear levels of podocyte transcription factors were reduced on loss of NUP93. Loss of NUP93 changed transcriptional programs in podocytes. BACKGROUND: Genetic variants in six different genes encoding nuclear pore complex (NPC) proteins cause steroid-resistant nephrotic syndrome and FSGS in pediatric patients. All affected proteins are structural components of NPCs, restricted channels across the nuclear envelope that are required for molecular exchange between nucleoplasm and cytoplasm. Although podocyte injury is a unifying feature of these genetic variants, the molecular mechanisms remain poorly understood. METHODS: To elucidate the pathogenesis of NPC protein-related podocyte injury, a mouse model with conditional knockout of the Nup93 gene was generated and studied. NPC density was measured by stimulated emission depletion microscopy. Transcriptomics, proteomics, and immunofluorescence analysis were used to define molecular pathogenic mechanisms. RESULTS: Knockout of Nup93 reduced NPC density in podocyte nuclei. While knockout of Nup93 during kidney development led to embryonic lethality, its deletion in mature podocytes ( NPHS2 -Cre) caused progressive glomerular disease with onset around 4 months of age, when a phenotype of minimal change glomerulopathy was observed. At this stage, immunofluorescence staining revealed reduced nuclear abundance of podocyte-specific transcription factors, which was due to cytoplasmic redistribution. Transcriptome and proteome analysis detected altered transcriptional regulation, prominently affecting genes related to cell adhesion and regulation of the actin cytoskeleton. Until 6 months of age, knockout mice developed progressive CKD with FSGS, podocyte loss, and uremia. Before induction of apoptosis, NUP93-deficient podocytes accumulated genomic damage as indicated by activation of the DNA damage response pathway. CONCLUSIONS: Our data suggest that in early stages of disease, loss of NUP93 impaired podocyte transcription factors and altered transcriptional programs in podocytes, prominently affecting regulators of the actin cytoskeleton. In the late stages, podocytes accumulated genomic damage, leading to apoptosis and progressive glomerulosclerosis.},
	doi = {10.1681/ASN.0000000964},
	pmid = {41563289}
}

@ARTICLE{10.1186/s12951-025-03967-x,
	author = {Huang M and Liu Y and Xiao T and Qi P and Shen W and Huo Y and Fu B and Hao J and Ao Q and Huo Y and Cai G and Chen X and Hong Q and Wu M and Feng Z},
	title = {Charge-dependent mitochondrial targeting of cerium-doped polypyrrole nanoparticles to injured renal tubules for acute kidney injury therapy.},
	journal = {J Nanobiotechnology},
	year = {2025},
	abstract = {Acute kidney injury (AKI) is a critical medical condition with limited treatment options and frequently progresses to chronic kidney disease (CKD). This study introduces a novel nanotherapeutic approach based on positively charged cerium-doped polypyrrole nanoparticles [(+)CePPy] for AKI treatment. The positive surface charge of these nanoparticles enhances their cellular uptake and mitochondrial targeting in proximal tubular epithelial cells (PTECs), which play a central role in the pathophysiology of AKI. Comprehensive in vitro and in vivo evaluations demonstrate that (+)CePPy effectively scavenges reactive oxygen species (ROS), ameliorates mitochondrial dysfunction, attenuates apoptosis, and prevents AKI-to-CKD progression. The nanoparticles exhibit excellent biocompatibility and undergo efficient renal clearance within 14 days. Mechanistically, the renoprotective effects involve both direct elimination of ROS and the reinforcement of endogenous antioxidant defenses through upregulation of the Mpv17 mitochondrial membrane protein-like (Mpv17l) pathway. Furthermore, we report that early endosome antigen 1 (EEA1) upregulation mediates the enhanced renal targeting of (+)CePPy under AKI conditions. This research highlights the potential of charge-modulated nanotherapeutics as a translatable strategy for renal protection and presents a promising approach for AKI treatment. GRAPHICAL ABSTRACT: [Image: see text] SUPPLEMENTARY INFORMATION: The online version contains supplementary material available at 10.1186/s12951-025-03967-x.},
	doi = {10.1186/s12951-025-03967-x},
	pmid = {41449392},
	note = {PMC12853839}
}

@ARTICLE{10.1002/advs.202512278,
	author = {Xu Y and Wang Y and Jiang S and Li Y and Li G and Liu Y and Li S and Zhou Y and Liu Q and Zhou Y and Chen W and Li H and Mao H},
	title = {Tubule-Derived IFN-α Promotes GSDMD-Mediated Macrophage Pyroptosis to Drive Renal Inflammation and Fibrosis Through JAK2/STAT2 Activation.},
	journal = {Adv Sci (Weinh)},
	year = {2026},
	abstract = {Macrophages exhibit high plasticity in response to tubular epithelial cell (TEC) injury. Gasdermin D (GSDMD)-mediated pyroptosis amplifies the inflammatory and fibrogenic cascade, yet its role in chronic kidney disease (CKD) remains elusive. Herein, GSDMD is upregulated in kidney macrophages following unilateral renal ischemia-reperfusion injury (UIRI) or folic acid-induced injury, paralleling elevated pyroptosis rates. Clinically, the active fragment GSDMD-N localizes primarily to CD68+ macrophages, and its renal level positively correlates with fibrosis severity across diverse CKD etiologies, reinforcing its pathogenic relevance. Macrophage-specific deletion of Gsdmd ameliorates pyroptosis, inflammation, and renal fibrosis in both murine models, without affecting acute tubular damage in bilateral IRI. Mechanistically, injured TECs initiate this cascade through secreted IFN-α, which activates the IFNAR1/JAK2/STAT2 axis in macrophages​. STAT2 then forms a complex with IRF9, directly binding to the Gsdmd promoter to transcriptionally upregulate GSDMD expression. Genetic ablation of Jak2, Stat2, or Ifnar1 reduces GSDMD and GSDMD-N levels and inhibits IL-1β/IL-18 secretion. Notably, administration of an IFN-α neutralizing antibody attenuates UIRI-induced pyroptotic macrophage, inflammation, and renal fibrosis. Collectively, the findings uncover a STAT2/IRF9-dependent paracrine IFN-α feedback loop that orchestrates GSDMD-mediated pyroptosis, linking injured TECs to macrophage-driven renal inflammation and fibrosis. Targeting this axis represents a promising strategy to halt CKD progression.},
	doi = {10.1002/advs.202512278},
	pmid = {41387110 [Indexed for MEDLINE]},
	note = {PMC12931230}
}

@ARTICLE{10.7150/thno.112905,
	author = {Xie M and Fu X and Lan Y and Zhang Y and Li H and Su Y and Zhou K and Zhang Y and Ding X and He J and Mao Z},
	title = {Spatially selective clearance of inflammation-mediated reactive oxygen species in injured kidney cells.},
	abstract = {Rationale: Kidney injury is characterized by the accumulation of reactive oxygen species (ROS). Current ROS scavengers utilized in the treatment of clinical kidney injury lack the capacity for spatially selective ROS scavenging within the injured cells, often resulting in irreversible damage to healthy tissues. Methods: We developed a spatially selective therapeutic strategy using platelet-shipped tetrahedral framework nucleic acids (TFNAs@PLT). Results: In this system, platelets achieve spatial targeting of injured kidney cells by responding to inflammatory signals and releasing TFNAs following TNF-α activation. TFNAs subsequently exert a potent antioxidant effect in the injured cells. We have demonstrated that TFNAs@PLT reduces pyroptosis and apoptosis through the Caspase-3/GSDME pathway and the NLRP3-mediated Caspase-1/IL-1β pathway in the acute kidney injury (AKI) mouse model, while also inhibiting renal fibrosis via the NLRP3/Caspase-1 and the TNF-α/NF-κB pathways in the chronic kidney disease (CKD) mouse model. Conclusion: TFNAs@PLT offers a safe and effective therapeutic strategy for kidney injury and other inflammation-mediated diseases.},
	doi = {10.7150/thno.112905},
	pmid = {41355960 [Indexed for MEDLINE]},
	note = {PMC12679581}
}

